class Solution:
    def minRemoveToMakeValid(self, s: str) -> str:
        # Step 1: Identify and mark invalid ')'
        # We use a stack to keep track of the indices of open parentheses.
        # When a closing parenthesis is encountered:
        # If the stack is not empty, it means there's an unmatched open parenthesis. Pop from stack.
        # If the stack is empty, this closing parenthesis has no matching open parenthesis, so it's invalid.
        # We mark invalid characters by replacing them with an empty string temporarily.

        stack = []  # Stores indices of '('
        chars = list(s)  # Convert string to a list of characters for mutability

        for i, char in enumerate(chars):
            if char == '(':
                stack.append(i)
            elif char == ')':
                if stack:
                    stack.pop()  # Found a match for an opening parenthesis
                else:
                    # This ')' is invalid, mark for removal
                    chars[i] = ''  # Replace with empty string

        # Step 2: Identify and mark invalid '('
        # Any remaining indices in the stack correspond to unmatched open parentheses.
        # These are also invalid and must be removed.

        while stack:
            invalid_open_idx = stack.pop()
            chars[invalid_open_idx] = ''  # Mark by replacing with empty string

        # Step 3: Join the valid characters to form the result string
        return "".join(chars)
